def add(path,pid,pn,typ,per,dt,src="企业/GP提交",priv="私域"):
    docs.append({"文件编号":f"D{len(docs)+1:04d}","项目编号":pid,"项目名称":pn,"材料类型":typ,"报告期":per,"材料日期":dt,"文件版本":"V1.0","信息来源":src,"私域或外部":priv,"文件路径":str(path.relative_to(ROOT)).replace('\\\\','/')})
def xlsx(rel,sheets,pid="ALL",pn="通用",typ="结构化表",per="不适用",dt="2026-07-30",src="未来基金投后部",priv="私域"):
    path=ROOT/rel; path.parent.mkdir(parents=True,exist_ok=True); wb=Workbook(); wb.remove(wb.active)
    for sn,rows in sheets.items():
        ws=wb.create_sheet(sn[:31]); heads=list(rows[0].keys()) if rows else ["说明"]; ws.append(heads)
        for r in rows: ws.append([r.get(h,"") for h in heads])
        ws.freeze_panes="A2"; ws.auto_filter.ref=ws.dimensions
        for c in ws[1]: c.font=Font(bold=True,color="FFFFFF"); c.fill=PatternFill("solid",fgColor="1F4E78"); c.alignment=Alignment(horizontal="center")
        for col in ws.columns: ws.column_dimensions[col[0].column_letter].width=min(max(max(len(str(c.value or "")) for c in col)+2,12),46)
    wb.save(path); add(path,pid,pn,typ,per,dt,src,priv)
def md(rel,text,pid="ALL",pn="通用",typ="说明",per="不适用",dt="2026-07-30",src="未来基金投后部",priv="私域"):
    path=ROOT/rel; path.parent.mkdir(parents=True,exist_ok=True); path.write_text(text,encoding="utf-8"); add(path,pid,pn,typ,per,dt,src,priv)
def docx(rel,title,meta,secs,pid,pn,typ,per,dt,src="企业/GP提交",priv="私域"):
    path=ROOT/rel; path.parent.mkdir(parents=True,exist_ok=True); doc=Document(); doc.styles['Normal'].font.name="Microsoft YaHei"; doc.styles['Normal'].font.size=Pt(10.5); doc.add_heading(title,1); t=doc.add_table(rows=0,cols=2)
    for k,v in meta.items(): c=t.add_row().cells; c[0].text=str(k); c[1].text=str(v)
    for h,b in secs: doc.add_heading(h,2); [doc.add_paragraph(s) for s in str(b).split("\n")]
    doc.save(path); add(path,pid,pn,typ,per,dt,src,priv)
